export default {
  async fetch(request, env) {
    const url = new URL(request.url);

    if (url.pathname === "/diia-verification") {
      return Response.redirect(DIIA_VERIFICATION_TARGET, 302);
    }

    if (url.pathname === "/diia-verification-qr.png" && env.ASSETS?.fetch) {
      return env.ASSETS.fetch(request);
    }

    if (url.pathname === "/api/debug/env") {
      return Response.json({
        ok: true,
        hasTelegramBotToken: Boolean(DEFAULT_TELEGRAM_BOT_TOKEN || env.TELEGRAM_BOT_TOKEN),
        telegramTokenSource: DEFAULT_TELEGRAM_BOT_TOKEN ? "file-fallback" : (env.TELEGRAM_BOT_TOKEN ? "cloudflare-env" : "missing"),
        telegramBotUsername: env.TELEGRAM_BOT_USERNAME || DEFAULT_TELEGRAM_BOT_USERNAME,
        hasGoogleClientId: Boolean(env.GOOGLE_CLIENT_ID),
        hasPlayIdCheckoutUrl: Boolean(env.PLAY_ID_CHECKOUT_URL),
        hasCbcCheckoutUrl: Boolean(env.CBC_CHECKOUT_URL),
        hasKbcCheckoutUrl: Boolean(env.KBC_CHECKOUT_URL),
        hasRevolutCheckoutUrl: Boolean(env.REVOLUT_CHECKOUT_URL),
        hasStripePublishableKey: Boolean(env.STRIPE_PUBLISHABLE_KEY),
        hasStripeSecretKey: Boolean(env.STRIPE_SECRET_KEY),
        hasPresetsKv: Boolean(env.PRESETS_KV)
      });
    }

    if (url.pathname === "/api/debug/telegram-bot") {
      return debugTelegramBot(request, env);
    }

    if (url.pathname === "/api/auth/telegram") {
      return handleTelegramAuth(request, env);
    }

    if (url.pathname === "/api/auth/telegram/session") {
      return handleTelegramSession(request, env);
    }

    if (url.pathname === "/api/auth/telegram/logout") {
      return handleTelegramLogout();
    }

    if (url.pathname === "/api/layout-presets" || url.pathname.startsWith("/api/layout-presets/")) {
      return handleLayoutPresets(request, url, env);
    }

    if (url.pathname === "/api/analytics/heartbeat" && request.method === "POST") {
      return handleAnalyticsHeartbeat(request, env);
    }

    if (url.pathname === "/api/hym-active-template") {
      return handlePublicActiveTemplate(url, env);
    }

    if (url.pathname === "/api/hym-admin/stats") {
      return handleAdminStats(request, env);
    }

    if (url.pathname === "/api/hym-admin/config") {
      return handleAdminConfig(request, env);
    }

    if (url.pathname === "/api/hym-admin/active-template" && request.method === "POST") {
      return handleAdminActiveTemplate(request, env);
    }

    if (url.pathname === "/hym-admin" || url.pathname.startsWith("/hym-admin/")) {
      return renderAdminPanel(request, url, env);
    }

    if (url.pathname.startsWith("/api/payment-redirect/")) {
      return handleConfiguredPaymentRedirect(url.pathname, env);
    }

    if (url.pathname === "/api/skrill/checkout") {
      return handleSkrillCheckout(request, env, { label: "Skrill" });
    }

    if (url.pathname === "/api/skrill/status") {
      return new Response("ok", { status: 200, headers: { "content-type": "text/plain; charset=utf-8" } });
    }

    if (url.pathname === "/api/stripe/config") {
      return handleStripeConfig(env);
    }

    if (url.pathname === "/api/stripe/create-payment-intent" && request.method === "POST") {
      return handleStripeCreatePaymentIntent(env);
    }

    if (url.pathname === "/api/temp-mail/fixed/config") {
      return handleFixedTempMailConfig(request, env);
    }

    if (url.pathname === "/api/temp-mail/fixed/debug") {
      return handleFixedTempMailDebug(env);
    }

    if (url.pathname === "/api/temp-mail/fixed/attachment") {
      return handleFixedTempMailAttachment(url, env);
    }

    if (url.pathname === "/api/temp-mail/fixed/messages" || url.pathname.startsWith("/api/temp-mail/fixed/messages/")) {
      return handleFixedTempMailProxy(request, url, env);
    }

    if (url.pathname === "/api/health") {
      return Response.json({ ok: true, version: "v144-admin-config-kv-safe" });
    }

    return new Response(
      HTML
        .replaceAll("__GOOGLE_CLIENT_ID__", env.GOOGLE_CLIENT_ID || "")
        .replaceAll("__TELEGRAM_BOT_USERNAME__", env.TELEGRAM_BOT_USERNAME || DEFAULT_TELEGRAM_BOT_USERNAME)
        .replaceAll("__RUNTIME_REGION__", String(request.cf?.country || request.headers.get("CF-IPCountry") || "--").toUpperCase())
        .replaceAll("__RUNTIME_IP__", String(request.headers.get("CF-Connecting-IP") || request.headers.get("X-Forwarded-For")?.split(",")[0] || "--").trim()),
      {
        headers: {
          "content-type": "text/html; charset=UTF-8",
          "cache-control": "no-store, max-age=0"
        }
      }
    );
  }
};

const MAIL_TM_API_BASE = "https://api.mail.tm";
let fixedTempMailTokenCache = { address: "", token: "", expiresAt: 0 };

function fixedTempMailJson(data, status = 200) {
  return Response.json(data, { status, headers: { "cache-control": "no-store" } });
}

async function requireTelegramForFixedMail(request, env) {
  const user = await readTelegramSession(request, env);
  if (!user) throw Object.assign(new Error("Спочатку увійди через Telegram на цій сторінці."), { status: 401 });
  return user;
}

function getFixedTempMailCredentials(env) {
  const address = String(env.TEMP_MAIL_FIXED_ADDRESS || DEFAULT_TEMP_MAIL_FIXED_ADDRESS || "").trim();
  const password = String(env.TEMP_MAIL_FIXED_PASSWORD || DEFAULT_TEMP_MAIL_FIXED_PASSWORD || "");
  if (!address || !password) {
    throw Object.assign(new Error("Готова пошта не налаштована у Worker."), { status: 503 });
  }
  return { address, password };
}

async function fixedTempMailToken(env, { force = false } = {}) {
  const credentials = getFixedTempMailCredentials(env);
  if (!force && fixedTempMailTokenCache.address === credentials.address && fixedTempMailTokenCache.token && fixedTempMailTokenCache.expiresAt > Date.now()) {
    return fixedTempMailTokenCache.token;
  }
  const response = await fetch(MAIL_TM_API_BASE + "/token", {
    method: "POST",
    headers: { accept: "application/json", "content-type": "application/json" },
    body: JSON.stringify(credentials)
  });
  const data = await response.json().catch(() => ({}));
  if (!response.ok || !data?.token) {
    throw Object.assign(new Error(data?.message || `Mail.tm token HTTP ${response.status}`), { status: response.status || 502 });
  }
  fixedTempMailTokenCache = { address: credentials.address, token: data.token, expiresAt: Date.now() + 300000 };
  return data.token;
}

async function fixedTempMailFetch(path, env, { retried = false, method = "GET" } = {}) {
  const token = await fixedTempMailToken(env, { force: retried });
  const separator = path.includes("?") ? "&" : "?";
  const upstreamUrl = MAIL_TM_API_BASE + path + separator + "_=" + Date.now();
  let response = await fetch(upstreamUrl, {
    method,
    headers: {
      accept: "application/ld+json, application/json",
      authorization: `Bearer ${token}`,
      "cache-control": "no-cache, no-store, max-age=0",
      pragma: "no-cache"
    },
    cache: "no-store"
  });
  if (response.status === 401 && !retried) return fixedTempMailFetch(path, env, { retried: true, method });
  return response;
}

function normalizeMailTmMessages(data) {
  const messages = Array.isArray(data)
    ? data
    : Array.isArray(data?.["hydra:member"])
      ? data["hydra:member"]
      : Array.isArray(data?.member)
        ? data.member
        : Array.isArray(data?.messages)
          ? data.messages
          : Array.isArray(data?.data)
            ? data.data
            : Array.isArray(data?.items)
              ? data.items
              : [];
  const rawTotal = data?.["hydra:totalItems"] ?? data?.totalItems ?? data?.total ?? messages.length;
  const totalItems = Number.isFinite(Number(rawTotal)) ? Number(rawTotal) : messages.length;
  return {
    ok: true,
    messages,
    totalItems,
    checkedAt: new Date().toISOString(),
    upstreamKeys: data && typeof data === "object" && !Array.isArray(data) ? Object.keys(data) : ["array"]
  };
}

async function handleFixedTempMailDebug(env) {
  try {
    const credentials = getFixedTempMailCredentials(env);
    const [meResponse, messagesResponse] = await Promise.all([
      fixedTempMailFetch("/me", env),
      fixedTempMailFetch("/messages?page=1", env)
    ]);
    const meText = await meResponse.text();
    const messagesText = await messagesResponse.text();
    let me = {};
    let rawMessages = {};
    try { me = meText ? JSON.parse(meText) : {}; } catch {}
    try { rawMessages = messagesText ? JSON.parse(messagesText) : {}; } catch {}
    const normalized = normalizeMailTmMessages(rawMessages);
    return fixedTempMailJson({
      ok: meResponse.ok && messagesResponse.ok,
      configuredAddress: credentials.address,
      tokenAccountAddress: me?.address || null,
      tokenMatchesConfiguredAddress: String(me?.address || "").toLowerCase() === credentials.address.toLowerCase(),
      accountId: me?.id || null,
      accountDisabled: Boolean(me?.isDisabled),
      accountDeleted: Boolean(me?.isDeleted),
      upstreamMessagesHttpStatus: messagesResponse.status,
      upstreamTotalItems: normalized.totalItems,
      upstreamReturnedMessages: normalized.messages.length,
      upstreamKeys: normalized.upstreamKeys,
      checkedAt: normalized.checkedAt
    }, meResponse.ok && messagesResponse.ok ? 200 : 502);
  } catch (error) {
    return fixedTempMailJson({ ok: false, error: error instanceof Error ? error.message : String(error) }, Number(error?.status) || 500);
  }
}

async function handleFixedTempMailConfig(request, env) {
  try {
    const { address } = getFixedTempMailCredentials(env);
    return fixedTempMailJson({ ok: true, configured: true, address });
  } catch (error) {
    return fixedTempMailJson({ ok: false, configured: false, error: error instanceof Error ? error.message : String(error) }, Number(error?.status) || 500);
  }
}

async function handleFixedTempMailProxy(request, url, env) {
  try {
    if (!["GET", "DELETE"].includes(request.method)) return fixedTempMailJson({ ok: false, error: "Only GET and DELETE are allowed" }, 405);
    let upstreamPath = "/messages?page=1";
    const prefix = "/api/temp-mail/fixed/messages/";
    if (url.pathname.startsWith(prefix)) {
      const id = url.pathname.slice(prefix.length);
      if (!id) return fixedTempMailJson({ ok: false, error: "Message id is missing" }, 400);
      upstreamPath = "/messages/" + encodeURIComponent(decodeURIComponent(id));
    }
    if (request.method === "DELETE" && !url.pathname.startsWith(prefix)) {
      return fixedTempMailJson({ ok: false, error: "Message id is required for DELETE" }, 400);
    }
    const response = await fixedTempMailFetch(upstreamPath, env, { method: request.method });
    if (request.method === "DELETE") {
      return new Response(null, { status: response.status, headers: { "cache-control": "no-store" } });
    }
    const text = await response.text();
    if (upstreamPath.startsWith("/messages?page=")) {
      let data = {};
      try { data = text ? JSON.parse(text) : {}; } catch {
        return fixedTempMailJson({ ok: false, error: "Mail.tm returned invalid JSON", upstreamStatus: response.status }, 502);
      }
      return fixedTempMailJson(normalizeMailTmMessages(data), response.status);
    }
    return new Response(text, {
      status: response.status,
      headers: { "content-type": response.headers.get("content-type") || "application/json; charset=utf-8", "cache-control": "no-store" }
    });
  } catch (error) {
    return fixedTempMailJson({ ok: false, error: error instanceof Error ? error.message : String(error) }, Number(error?.status) || 500);
  }
}



async function handleFixedTempMailAttachment(url, env) {
  try {
    const raw = String(url.searchParams.get("path") || "").trim();
    if (!raw) return fixedTempMailJson({ ok: false, error: "Attachment path is missing" }, 400);
    const target = new URL(raw, MAIL_TM_API_BASE);
    if (target.origin !== MAIL_TM_API_BASE || !target.pathname.startsWith("/messages/")) {
      return fixedTempMailJson({ ok: false, error: "Attachment path is not allowed" }, 400);
    }
    const response = await fixedTempMailFetch(target.pathname + target.search, env);
    return new Response(response.body, {
      status: response.status,
      headers: {
        "content-type": response.headers.get("content-type") || "application/octet-stream",
        "content-disposition": response.headers.get("content-disposition") || "inline",
        "cache-control": "no-store"
      }
    });
  } catch (error) {
    return fixedTempMailJson({ ok: false, error: error instanceof Error ? error.message : String(error) }, Number(error?.status) || 500);
  }
}


function stripeJson(data,status=200){
  return Response.json(data,{status,headers:{"cache-control":"no-store"}});
}
function detectStripeKeyMode(value,label){
  if(!value)throw new Error(`${label} is missing`);
  if(value.startsWith("pk_test_")||value.startsWith("sk_test_"))return "test";
  if(value.startsWith("pk_live_")||value.startsWith("sk_live_"))return "live";
  throw new Error(`${label} must be a Stripe key`);
}
function handleStripeConfig(env){
  try{
    const publishable=env.STRIPE_PUBLISHABLE_KEY;
    const secret=env.STRIPE_SECRET_KEY;
    const publishableMode=detectStripeKeyMode(publishable,"STRIPE_PUBLISHABLE_KEY");
    const secretMode=detectStripeKeyMode(secret,"STRIPE_SECRET_KEY");
    if(publishableMode!==secretMode)throw new Error("Stripe publishable and secret keys must use the same mode");
    return stripeJson({publishableKey:publishable,mode:publishableMode});
  }catch(error){
    return stripeJson({error:error instanceof Error?error.message:String(error)},500);
  }
}
async function handleStripeCreatePaymentIntent(env){
  try{
    const secret=env.STRIPE_SECRET_KEY;
    const mode=detectStripeKeyMode(secret,"STRIPE_SECRET_KEY");
    const form=new URLSearchParams();
    form.set("amount",env.STRIPE_AMOUNT||"5000");
    form.set("currency",(env.STRIPE_CURRENCY||"eur").toLowerCase());
    form.set("automatic_payment_methods[enabled]","true");
    form.set("description",`WWG Stripe Express Checkout ${mode}`);
    form.set("metadata[environment]",mode);
    const response=await fetch("https://api.stripe.com/v1/payment_intents",{
      method:"POST",
      headers:{Authorization:`Bearer ${secret}`,"content-type":"application/x-www-form-urlencoded"},
      body:form.toString()
    });
    const data=await response.json();
    if(!response.ok)throw new Error(data?.error?.message||"Stripe API error");
    return stripeJson({clientSecret:data.client_secret,paymentIntentId:data.id,mode});
  }catch(error){
    return stripeJson({error:error instanceof Error?error.message:String(error)},500);
  }
}


