function handleConfiguredPaymentRedirect(pathname, env) {
  const config = PAYMENT_REDIRECTS[pathname];
  if (!config) {
    return new Response("Unknown payment redirect", { status: 404, headers: { "content-type": "text/plain; charset=utf-8" } });
  }
  const [envName, label, fallbackUrl] = config;
  const rawUrl = env[envName] || fallbackUrl;
  if (!rawUrl) {
    return new Response(`${label} checkout URL is not configured. Set Cloudflare secret ${envName} and try again.`, { status: 503, headers: { "content-type": "text/plain; charset=utf-8" } });
  }
  try {
    const target = new URL(rawUrl);
    if (target.protocol !== "https:") throw new Error("only HTTPS checkout URLs are allowed");
    return Response.redirect(target.toString(), 302);
  } catch (error) {
    return new Response(`${label} checkout URL is invalid: ${error instanceof Error ? error.message : String(error)}`, { status: 500, headers: { "content-type": "text/plain; charset=utf-8" } });
  }
}


async function handleSkrillCheckout(request, env, options = {}) {
  const requestUrl = new URL(request.url);
  const origin = requestUrl.origin;

  // Every Skrill SID is short-lived. Generate a fresh session for each click.
  // Set SKRILL_PAY_TO_EMAIL in Cloudflare for your merchant account.
  // The fallback below is Skrill's public demo merchant and is suitable only for QA.
  const payToEmail = env.SKRILL_PAY_TO_EMAIL || "demoqco@sun-fish.com";
  const amount = env.SKRILL_AMOUNT || "1.00";
  const currency = env.SKRILL_CURRENCY || "EUR";
  const language = env.SKRILL_LANGUAGE || "EN";
  const label = options.label || "Skrill";
  const paymentMethods = options.paymentMethods || "";
  const payFromEmail = env.SKRILL_PAY_FROM_EMAIL || "";

  const form = new URLSearchParams();
  form.set("pay_to_email", payToEmail);
  form.set("amount", amount);
  form.set("currency", currency);
  form.set("language", language);
  if (paymentMethods) form.set("payment_methods", paymentMethods);
  if (payFromEmail) form.set("pay_from_email", payFromEmail);
  form.set("prepare_only", "1");
  form.set("transaction_id", `qa-${Date.now()}-${crypto.randomUUID()}`);
  form.set("recipient_description", env.SKRILL_RECIPIENT_DESCRIPTION || `WWG QA Team - ${label}`);
  form.set("return_url", `${origin}/?skrill_checkout=return`);
  form.set("cancel_url", `${origin}/?skrill_checkout=cancel`);
  form.set("status_url", `${origin}/api/skrill/status`);

  try {
    const response = await fetch("https://pay.skrill.com", {
      method: "POST",
      headers: { "content-type": "application/x-www-form-urlencoded" },
      body: form.toString()
    });

    const sid = (await response.text()).trim();
    if (!response.ok || !/^[A-Za-z0-9_-]{8,200}$/.test(sid)) {
      return new Response(
        `Skrill session creation failed. HTTP ${response.status}. Response: ${sid.slice(0, 300)}`,
        { status: 502, headers: { "content-type": "text/plain; charset=utf-8" } }
      );
    }

    return Response.redirect(`https://pay.skrill.com/?sid=${encodeURIComponent(sid)}`, 302);
  } catch (error) {
    return new Response(
      `Skrill session creation failed: ${error instanceof Error ? error.message : String(error)}`,
      { status: 502, headers: { "content-type": "text/plain; charset=utf-8" } }
    );
  }
}

async function debugTelegramBot(request, env) {
  const configuredWidgetUsername = env.TELEGRAM_BOT_USERNAME || DEFAULT_TELEGRAM_BOT_USERNAME;
  const token = DEFAULT_TELEGRAM_BOT_TOKEN || env.TELEGRAM_BOT_TOKEN;
  const tokenSource = DEFAULT_TELEGRAM_BOT_TOKEN ? "file-fallback" : (env.TELEGRAM_BOT_TOKEN ? "cloudflare-env" : "missing");

  if (!token) {
    return Response.json({
      ok: false,
      tokenSource,
      configuredWidgetUsername,
      error: "missing telegram bot token"
    }, { status: 500 });
  }

  try {
    const res = await fetch(`https://api.telegram.org/bot${token}/getMe`);
    const data = await res.json();

    if (!res.ok || !data.ok) {
      return Response.json({
        ok: false,
        tokenSource,
        configuredWidgetUsername,
        telegramApiOk: data.ok || false,
        error: data.description || "Telegram getMe failed"
      }, { status: 500 });
    }

    const actualUsername = data.result && data.result.username ? data.result.username : "";
    return Response.json({
      ok: true,
      tokenSource,
      configuredWidgetUsername,
      actualBotUsernameFromToken: actualUsername,
      matchesWidget: actualUsername.toLowerCase() === configuredWidgetUsername.toLowerCase(),
      botId: data.result.id,
      botFirstName: data.result.first_name,
      canJoinGroups: data.result.can_join_groups,
      canReadAllGroupMessages: data.result.can_read_all_group_messages,
      supportsInlineQueries: data.result.supports_inline_queries
    });
  } catch (error) {
    return Response.json({
      ok: false,
      tokenSource,
      configuredWidgetUsername,
      error: error instanceof Error ? error.message : String(error)
    }, { status: 500 });
  }
}


function utf8ToBase64Url(value) {
  const bytes = new TextEncoder().encode(value);
  let binary = "";
  for (const byte of bytes) binary += String.fromCharCode(byte);
  return btoa(binary)
    .replace(/\+/g, "-")
    .replace(/\//g, "_")
    .replace(/=+$/g, "");
}

function base64UrlToUtf8(value) {
  const normalized = value.replace(/-/g, "+").replace(/_/g, "/");
  const padded = normalized + "=".repeat((4 - (normalized.length % 4)) % 4);
  const binary = atob(padded);
  const bytes = Uint8Array.from(binary, (char) => char.charCodeAt(0));
  return new TextDecoder().decode(bytes);
}

function getCookie(request, name) {
  const header = request.headers.get("Cookie") || "";
  for (const part of header.split(";")) {
    const trimmed = part.trim();
    if (trimmed.startsWith(`${name}=`)) return trimmed.slice(name.length + 1);
  }
  return "";
}

function constantTimeEqual(left, right) {
  if (typeof left !== "string" || typeof right !== "string" || left.length !== right.length) return false;
  let diff = 0;
  for (let i = 0; i < left.length; i++) diff |= left.charCodeAt(i) ^ right.charCodeAt(i);
  return diff === 0;
}

async function signTelegramSession(payload, botToken) {
  if (!botToken) throw new Error("missing Telegram bot token");
  return hmacSha256Hex(await sha256(botToken), payload);
}

async function readTelegramSession(request, env) {
  const raw = getCookie(request, "wwg_tg_session");
  if (!raw) return null;
  const separator = raw.lastIndexOf(".");
  if (separator <= 0) return null;
  const payload = raw.slice(0, separator);
  const receivedSignature = raw.slice(separator + 1);
  const botToken = DEFAULT_TELEGRAM_BOT_TOKEN || env.TELEGRAM_BOT_TOKEN;
  const expectedSignature = await signTelegramSession(payload, botToken);
  if (!constantTimeEqual(receivedSignature, expectedSignature)) return null;
  const user = JSON.parse(base64UrlToUtf8(payload));
  if (!user.loginAt || Date.now() - Number(user.loginAt) > 604800000) return null;
  return user;
}

async function handleTelegramSession(request, env) {
  try {
    const user = await readTelegramSession(request, env);
    if (!user) return Response.json({ ok: false, authenticated: false }, { headers: { "cache-control": "no-store" } });
    return Response.json({ ok: true, authenticated: true, user }, { headers: { "cache-control": "no-store" } });
  } catch (error) {
    return Response.json({ ok: false, authenticated: false }, { headers: { "cache-control": "no-store" } });
  }
}

function handleTelegramLogout() {
  return new Response(null, {
    status: 204,
    headers: {
      "Set-Cookie": "wwg_tg_session=; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=0",
      "cache-control": "no-store"
    }
  });
}

async function handleTelegramAuth(request, env) {
  const url = new URL(request.url);
  const params = Object.fromEntries(url.searchParams.entries());

  const verification = await verifyTelegramAuth(params, DEFAULT_TELEGRAM_BOT_TOKEN || env.TELEGRAM_BOT_TOKEN);

  if (!verification.ok) {
    return new Response(`Telegram auth failed: ${verification.reason}`, {
      status: 401,
      headers: {
        "content-type": "text/plain; charset=utf-8"
      }
    });
  }

  const now = Math.floor(Date.now() / 1000);
  const authDate = Number(params.auth_date);

  if (!authDate || now - authDate > 86400) {
    return new Response("Telegram auth failed: expired auth_date", {
      status: 401,
      headers: {
        "content-type": "text/plain; charset=utf-8"
      }
    });
  }

  const user = {
    telegramId: params.id,
    firstName: params.first_name || "",
    lastName: params.last_name || "",
    username: params.username || "",
    photoUrl: params.photo_url || ""
  };

  let sessionPayload;
  try {
    sessionPayload = utf8ToBase64Url(JSON.stringify({
      telegramId: user.telegramId,
      username: user.username,
      firstName: user.firstName,
      photoUrl: user.photoUrl,
      loginAt: Date.now()
    }));
  } catch (error) {
    return new Response(
      `Telegram auth failed: session encoding error: ${error instanceof Error ? error.message : String(error)}`,
      { status: 500, headers: { "content-type": "text/plain; charset=utf-8" } }
    );
  }

  let sessionSignature;
  try {
    sessionSignature = await signTelegramSession(sessionPayload, DEFAULT_TELEGRAM_BOT_TOKEN || env.TELEGRAM_BOT_TOKEN);
  } catch (error) {
    return new Response(
      `Telegram auth failed: session signing error: ${error instanceof Error ? error.message : String(error)}`,
      { status: 500, headers: { "content-type": "text/plain; charset=utf-8" } }
    );
  }

  const headers = new Headers();
  headers.append(
    "Set-Cookie",
    `wwg_tg_session=${sessionPayload}.${sessionSignature}; Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=604800`
  );
  headers.append("Location", "/?telegram_login=success");

  return new Response(null, { status: 302, headers });
}

async function verifyTelegramAuth(data, botToken) {
  if (!botToken) {
    return { ok: false, reason: "missing TELEGRAM_BOT_TOKEN env" };
  }

  const receivedHash = data.hash;
  if (!receivedHash) {
    return { ok: false, reason: "missing hash from Telegram" };
  }

  const dataCheckString = Object.keys(data)
    .filter((key) => key !== "hash")
    .sort()
    .map((key) => `${key}=${data[key]}`)
    .join("\n");

  const secretKey = await sha256(botToken);
  const calculatedHash = await hmacSha256Hex(secretKey, dataCheckString);

  if (calculatedHash !== receivedHash) {
    return {
      ok: false,
      reason: "hash mismatch: wrong bot token or wrong bot username. Check /api/debug/telegram-bot"
    };
  }

  return { ok: true, reason: "ok" };
}

async function sha256(text) {
  const encoder = new TextEncoder();
  return crypto.subtle.digest("SHA-256", encoder.encode(text));
}

async function hmacSha256Hex(secretKeyBuffer, text) {
  const encoder = new TextEncoder();
  const cryptoKey = await crypto.subtle.importKey(
    "raw",
    secretKeyBuffer,
    { name: "HMAC", hash: "SHA-256" },
    false,
    ["sign"]
  );
  const signature = await crypto.subtle.sign("HMAC", cryptoKey, encoder.encode(text));
  return [...new Uint8Array(signature)]
    .map((byte) => byte.toString(16).padStart(2, "0"))
    .join("");
}

// --- optional Cloudflare KV-backed HYM server presets ---
const HYM_PRESETS_INDEX_KEY = "hym:presets:index:v2";
const HYM_PRESET_PREFIX = "hym:preset:"; // legacy fallback only
const HYM_PRESETS_MAX_ITEMS = 40;

function hymPresetJson(data, status = 200) {
  return Response.json(data, { status, headers: { "cache-control": "no-store" } });
}

function hymPresetKv(env) {
  return env.PRESETS_KV && typeof env.PRESETS_KV.get === "function" ? env.PRESETS_KV : null;
}

function hymPresetSafeName(value) {
  return String(value || "").trim().replace(/\s+/g, " ").slice(0, 80);
}

function hymPresetId(value) {
  const id = String(value || "").trim();
  return /^[a-zA-Z0-9_-]{6,100}$/.test(id) ? id : "";
}

function hymPresetValidateProfile(profile) {
  if (!profile || typeof profile !== "object" || Array.isArray(profile)) {
    throw Object.assign(new Error("Preset profile must be a JSON object."), { status: 400 });
  }
  const serialized = JSON.stringify(profile);
  if (serialized.length > 120000) {
    throw Object.assign(new Error("Preset profile is too large."), { status: 413 });
  }
  return serialized;
}

function hymPresetNormalizeList(value) {
  const list = Array.isArray(value?.presets) ? value.presets : Array.isArray(value) ? value : [];
  return list.filter(item => item && typeof item === "object" && item.id && item.profile && typeof item.profile === "object")
    .sort((a, b) => Number(b.updatedAt || b.savedAt || 0) - Number(a.updatedAt || a.savedAt || 0))
    .slice(0, HYM_PRESETS_MAX_ITEMS);
}

async function hymPresetReadIndex(kv) {
  const data = await kv.get(HYM_PRESETS_INDEX_KEY, "json");
  return hymPresetNormalizeList(data);
}

async function hymPresetReadLegacy(kv) {
  const listed = await kv.list({ prefix: HYM_PRESET_PREFIX, limit: 100 });
  const items = await Promise.all((listed.keys || []).map(async ({ name }) => {
    const data = await kv.get(name, "json");
    return data && typeof data === "object" ? data : null;
  }));
  return hymPresetNormalizeList(items);
}

async function hymPresetReadAll(kv) {
  const indexed = await hymPresetReadIndex(kv);
  if (indexed.length) return { presets: indexed, source: "index" };
  const legacy = await hymPresetReadLegacy(kv);
  return { presets: legacy, source: legacy.length ? "legacy" : "empty" };
}

async function hymPresetWriteIndex(kv, presets) {
  const safe = hymPresetNormalizeList(presets);
  await kv.put(HYM_PRESETS_INDEX_KEY, JSON.stringify({ version: 2, updatedAt: Date.now(), presets: safe }));
  return safe;
}

async function hymPresetRequireTelegram(request, env) {
  const user = await readTelegramSession(request, env);
  if (!user) throw Object.assign(new Error("Увійди через Telegram перед записом серверного preset."), { status: 401 });
  return user;
}

async function handleLayoutPresets(request, url, env) {
  const kv = hymPresetKv(env);
  if (!kv) return hymPresetJson({ ok: false, configured: false, presets: [], error: "PRESETS_KV binding is not configured." }, 503);
  const suffix = decodeURIComponent(url.pathname.slice("/api/layout-presets".length)).replace(/^\/+/, "");
  try {
    if (request.method === "GET" && !suffix) {
      const { presets, source } = await hymPresetReadAll(kv);
      return hymPresetJson({ ok: true, configured: true, presets, source, storage: "single-index" });
    }
    if (request.method === "GET" && suffix) {
      const id = hymPresetId(suffix);
      if (!id) return hymPresetJson({ ok: false, error: "Invalid preset id." }, 400);
      const { presets } = await hymPresetReadAll(kv);
      const preset = presets.find(item => item.id === id) || null;
      return preset ? hymPresetJson({ ok: true, configured: true, preset }) : hymPresetJson({ ok: false, error: "Preset not found." }, 404);
    }
    if (request.method === "POST" && !suffix) {
      const user = await hymPresetRequireTelegram(request, env);
      const body = await request.json().catch(() => ({}));
      const name = hymPresetSafeName(body.name);
      if (!name) return hymPresetJson({ ok: false, error: "Preset name is required." }, 400);
      const serializedProfile = hymPresetValidateProfile(body.profile);
      const profileHash = String(body.profileHash || "").slice(0, 64);
      const { presets } = await hymPresetReadAll(kv);
      if (profileHash && presets[0]?.profileHash === profileHash) {
        return hymPresetJson({ ok: true, configured: true, skipped: true, reason: "same-profile", preset: presets[0], presets });
      }
      const id = crypto.randomUUID();
      const now = Date.now();
      const record = { id, name, profile: JSON.parse(serializedProfile), profileHash, savedAt: now, updatedAt: now, savedByTelegramId: String(user.telegramId || "") };
      const next = await hymPresetWriteIndex(kv, [record, ...presets.filter(item => item.id !== id)].slice(0, HYM_PRESETS_MAX_ITEMS));
      return hymPresetJson({ ok: true, configured: true, preset: record, presets: next, storage: "single-index" }, 201);
    }
    if (request.method === "DELETE" && suffix) {
      await hymPresetRequireTelegram(request, env);
      const id = hymPresetId(suffix);
      if (!id) return hymPresetJson({ ok: false, error: "Invalid preset id." }, 400);
      const { presets } = await hymPresetReadAll(kv);
      const next = await hymPresetWriteIndex(kv, presets.filter(item => item.id !== id));
      try { await kv.delete(HYM_PRESET_PREFIX + id); } catch {}
      return hymPresetJson({ ok: true, configured: true, deleted: id, presets: next, storage: "single-index" });
    }
    return hymPresetJson({ ok: false, error: "Method not allowed." }, 405);
  } catch (error) {
    return hymPresetJson({ ok: false, configured: true, error: error instanceof Error ? error.message : String(error) }, Number(error?.status) || 500);
  }
}
// --- /optional Cloudflare KV-backed HYM server presets ---


// --- v111 hidden HYM admin panel + lightweight KV analytics ---
const HYM_ANALYTICS_ONLINE_PREFIX = "hym:analytics:online:";
const HYM_ANALYTICS_DAY_PREFIX = "hym:analytics:day:";
const HYM_ANALYTICS_ONLINE_TTL_SECONDS = 150;
const HYM_ACTIVE_TEMPLATE_PREFIX = "hym:active-template:";

function hymAdminJson(data, status = 200) {
  return Response.json(data, { status, headers: { "cache-control": "no-store" } });
}

function hymAdminKv(env) {
  return env.PRESETS_KV && typeof env.PRESETS_KV.get === "function" ? env.PRESETS_KV : null;
}

function hymAdminSettingsKv(env) {
  return env.ADMIN_CONFIG_KV && typeof env.ADMIN_CONFIG_KV.get === "function" ? env.ADMIN_CONFIG_KV : hymAdminKv(env);
}

function hymAdminSettingsStorage(env) {
  return env.ADMIN_CONFIG_KV && typeof env.ADMIN_CONFIG_KV.get === "function" ? "ADMIN_CONFIG_KV" : "PRESETS_KV";
}


function hymAdminSecret(env) {
  return String(env.ADMIN_SECRET_KEY || env.ADMIN_KEY || env.HYM_ADMIN_KEY || env.ADMIN_SECRET || "").trim();
}

function hymSafeEqual(left, right) {
  const a = String(left || "");
  const b = String(right || "");
  if (!a || !b || a.length !== b.length) return false;
  let diff = 0;
  for (let i = 0; i < a.length; i += 1) diff |= a.charCodeAt(i) ^ b.charCodeAt(i);
  return diff === 0;
}

function hymAdminRequestKey(request, url = new URL(request.url)) {
  const pathKey = url.pathname.startsWith("/hym-admin/") ? decodeURIComponent(url.pathname.slice("/hym-admin/".length)).split("/")[0] : "";
  return String(request.headers.get("x-hym-admin-key") || url.searchParams.get("key") || pathKey || "").trim();
}

function hymRequireAdmin(request, env, url = new URL(request.url)) {
  const configured = hymAdminSecret(env);
  if (!configured) throw Object.assign(new Error("Cloudflare secret ADMIN_SECRET_KEY is not configured."), { status: 503 });
  if (!hymSafeEqual(hymAdminRequestKey(request, url), configured)) throw Object.assign(new Error("Admin access denied."), { status: 404 });
  return true;
}

function hymKyivDay(timestamp = Date.now()) {
  const parts = new Intl.DateTimeFormat("en-CA", { timeZone: "Europe/Kyiv", year: "numeric", month: "2-digit", day: "2-digit" }).formatToParts(new Date(timestamp));
  const get = type => parts.find(part => part.type === type)?.value || "";
  return `${get("year")}-${get("month")}-${get("day")}`;
}

function hymSafeVisitorId(value) {
  const id = String(value || "").trim();
  return /^[a-zA-Z0-9_-]{12,96}$/.test(id) ? id : "";
}

async function hymListAllKeys(kv, prefix) {
  const keys = [];
  let cursor;
  do {
    const page = await kv.list({ prefix, cursor, limit: 1000 });
    keys.push(...(page.keys || []));
    cursor = page.list_complete ? undefined : page.cursor;
  } while (cursor);
  return keys;
}

async function handleAnalyticsHeartbeat(request, env) {
  const kv = hymAdminKv(env);
  if (!kv) return hymAdminJson({ ok: false, error: "PRESETS_KV binding is not configured." }, 503);
  let body = {};
  try { body = await request.json(); } catch {}
  const visitorId = hymSafeVisitorId(body.visitorId);
  if (!visitorId) return hymAdminJson({ ok: false, error: "Invalid visitor id." }, 400);
  const now = Date.now();
  const day = hymKyivDay(now);
  await Promise.all([
    kv.put(HYM_ANALYTICS_ONLINE_PREFIX + visitorId, String(now), { expirationTtl: HYM_ANALYTICS_ONLINE_TTL_SECONDS }),
    kv.put(HYM_ANALYTICS_DAY_PREFIX + day + ":" + visitorId, String(now), { expirationTtl: 60 * 60 * 24 * 3 })
  ]);
  return hymAdminJson({ ok: true });
}

function hymAdminPlatform(value) {
  return value === "mobile" || value === "tablet" || value === "windows" ? value : "";
}

async function hymPresetFindById(kv, id) {
  const presetId = hymPresetId(id);
  if (!kv || !presetId) return null;
  const { presets } = await hymPresetReadAll(kv);
  return presets.find(item => item.id === presetId) || null;
}

async function handlePublicActiveTemplate(url, env) {
  const presetsKv = hymAdminKv(env);
  const settingsKv = hymAdminSettingsKv(env);
  const platform = hymAdminPlatform(url.searchParams.get("platform"));
  if (!presetsKv || !settingsKv || !platform) return hymAdminJson({ ok: true, platform, presetId: "", profile: null, storage: hymAdminSettingsStorage(env) });
  let presetId = String(await settingsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + platform) || "");
  if (!presetId && settingsKv !== presetsKv) presetId = String(await presetsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + platform) || "");
  if (!presetId) return hymAdminJson({ ok: true, platform, presetId: "", profile: null, storage: hymAdminSettingsStorage(env) });
  const preset = await hymPresetFindById(presetsKv, presetId);
  return hymAdminJson({ ok: true, platform, presetId, presetName: preset?.name || presetId, profile: preset?.profile || null, storage: hymAdminSettingsStorage(env) });
}

async function hymReadAdminStats(env) {
  const kv = hymAdminKv(env);
  if (!kv) throw Object.assign(new Error("PRESETS_KV binding is not configured."), { status: 503 });
  const now = Date.now();
  const today = hymKyivDay(now);
  const [onlineKeys, dayKeys] = await Promise.all([
    hymListAllKeys(kv, HYM_ANALYTICS_ONLINE_PREFIX),
    hymListAllKeys(kv, HYM_ANALYTICS_DAY_PREFIX + today + ":")
  ]);
  return { online: onlineKeys.length, today: dayKeys.length, day: today, onlineWindowSeconds: HYM_ANALYTICS_ONLINE_TTL_SECONDS, updatedAt: now };
}

async function hymReadActiveTemplates(env) {
  const presetsKv = hymAdminKv(env);
  const settingsKv = hymAdminSettingsKv(env);
  if (!presetsKv || !settingsKv) throw Object.assign(new Error("PRESETS_KV / ADMIN_CONFIG_KV binding is not configured."), { status: 503 });
  let [mobile, tablet, windows] = await Promise.all([
    settingsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + "mobile"),
    settingsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + "tablet"),
    settingsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + "windows")
  ]);
  if (settingsKv !== presetsKv && (!mobile || !tablet || !windows)) {
    const [legacyMobile, legacyTablet, legacyWindows] = await Promise.all([
      presetsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + "mobile"),
      presetsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + "tablet"),
      presetsKv.get(HYM_ACTIVE_TEMPLATE_PREFIX + "windows")
    ]);
    mobile = mobile || legacyMobile;
    tablet = tablet || legacyTablet;
    windows = windows || legacyWindows;
  }
  return { mobile: mobile || "", tablet: tablet || "", windows: windows || "" };
}

async function hymReadPresetSummaries(env) {
  const kv = hymAdminKv(env);
  if (!kv) throw Object.assign(new Error("PRESETS_KV binding is not configured."), { status: 503 });
  const { presets } = await hymPresetReadAll(kv);
  return presets
    .map(preset => ({
      id: preset.id,
      name: preset.name || preset.id,
      savedAt: preset.savedAt || preset.updatedAt || 0,
      updatedAt: preset.updatedAt || preset.savedAt || 0
    }))
    .sort((a, b) => Number(b.updatedAt || b.savedAt || 0) - Number(a.updatedAt || a.savedAt || 0));
}

async function handleAdminStats(request, env) {
  try { hymRequireAdmin(request, env); return hymAdminJson({ ok: true, stats: await hymReadAdminStats(env) }); }
  catch (error) { return hymAdminJson({ ok: false, error: error.message }, Number(error.status) || 500); }
}

async function handleAdminConfig(request, env) {
  try {
    hymRequireAdmin(request, env);
    const [stats, active, presets] = await Promise.all([hymReadAdminStats(env), hymReadActiveTemplates(env), hymReadPresetSummaries(env)]);
    return hymAdminJson({
      ok: true,
      stats,
      active,
      presets,
      bindings: {
        presetsKv: Boolean(hymAdminKv(env)),
        adminConfigKv: Boolean(env.ADMIN_CONFIG_KV && typeof env.ADMIN_CONFIG_KV.get === "function"),
        settingsStorage: hymAdminSettingsStorage(env)
      }
    });
  } catch (error) { return hymAdminJson({ ok: false, error: error.message }, Number(error.status) || 500); }
}

async function handleAdminActiveTemplate(request, env) {
  try {
    hymRequireAdmin(request, env);
    const presetsKv = hymAdminKv(env);
    const settingsKv = hymAdminSettingsKv(env);
    const body = await request.json();
    const platform = hymAdminPlatform(body.platform);
    const presetId = body.presetId ? hymPresetId(body.presetId) : "";
    if (!presetsKv || !settingsKv) return hymAdminJson({ ok: false, error: "PRESETS_KV / ADMIN_CONFIG_KV binding is not configured." }, 503);
    if (!platform) return hymAdminJson({ ok: false, error: "Invalid platform." }, 400);
    if (body.presetId && !presetId) return hymAdminJson({ ok: false, error: "Invalid preset id." }, 400);
    if (presetId) {
      const preset = await hymPresetFindById(presetsKv, presetId);
      if (!preset) return hymAdminJson({ ok: false, error: "Preset not found." }, 404);
      await settingsKv.put(HYM_ACTIVE_TEMPLATE_PREFIX + platform, presetId);
    } else {
      await settingsKv.delete(HYM_ACTIVE_TEMPLATE_PREFIX + platform);
    }
    return hymAdminJson({ ok: true, active: await hymReadActiveTemplates(env), storage: hymAdminSettingsStorage(env) });
  } catch (error) { return hymAdminJson({ ok: false, error: error.message }, Number(error.status) || 500); }
}

const HYM_ADMIN_HTML = `<!doctype html>
<html lang="uk"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>HYM Admin</title>
<style>:root{color-scheme:dark;--bg:#050708;--panel:#0b0f11;--line:#1c2a2f;--text:#d7f5ee;--muted:#7c9994;--green:#34ff9a;--red:#ff4d57}*{box-sizing:border-box}body{margin:0;background:radial-gradient(circle at 10% 0%,rgba(0,255,149,.07),transparent 32%),var(--bg);color:var(--text);font:13px/1.45 Consolas,monospace}.wrap{width:min(1620px,calc(100% - 22px));margin:0 auto;padding:14px 0}.top,.card{background:rgba(11,15,17,.97);border:1px solid var(--line);box-shadow:0 10px 24px rgba(0,0,0,.28)}.top{display:flex;justify-content:space-between;gap:10px;align-items:center;padding:12px}.brand{font-weight:900;letter-spacing:.15em;color:var(--green)}.build{display:inline-block;margin-left:8px;padding:2px 5px;border:1px solid #1b644e;color:#a8ffd1;font-size:9px;letter-spacing:.12em;vertical-align:middle}.muted{color:var(--muted)}.tablet-template{border-color:#1b644e}.tablet-template h2{color:#a8ffd1}.new-badge{display:inline-block;margin-left:7px;padding:2px 5px;border:1px solid #1b644e;color:var(--green);font-size:9px;letter-spacing:.08em;vertical-align:middle}.grid{display:grid;grid-template-columns:repeat(12,minmax(0,1fr));gap:12px;margin-top:12px}.card{grid-column:span 4;padding:14px;min-width:0}.stats{grid-column:span 4}.n{font-size:35px;font-weight:900;color:var(--green);line-height:1;margin:8px 0}.label,h2{font-size:11px;letter-spacing:.13em;text-transform:uppercase}h2{margin:0 0 10px;color:#e6fff8}.row{display:grid;grid-template-columns:minmax(120px,.42fr) minmax(0,1fr);gap:10px;align-items:center;margin-top:8px;min-width:0}.row .muted{min-width:0;overflow-wrap:anywhere}select,button{font:inherit;background:#11191c;border:1px solid #294146;color:var(--text);padding:10px}select{display:block;width:100%;max-width:100%;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;outline:none}select:focus{border-color:var(--green);box-shadow:0 0 0 2px rgba(52,255,154,.12)}option{background:#081011;color:#d7f5ee}button{cursor:pointer;font-weight:900;text-transform:uppercase}button:hover{border-color:var(--green)}.status{margin-top:10px;min-height:20px;color:var(--muted)}.ok{color:var(--green)}.err{color:var(--red)}@media(max-width:1100px){.card{grid-column:span 6}.stats{grid-column:span 4}.row{grid-template-columns:1fr}}@media(max-width:760px){.stats,.card{grid-column:1/-1}.top{align-items:flex-start;flex-direction:column}.top button{width:100%}.row{grid-template-columns:1fr}}</style></head>
<body><main class="wrap"><header class="top"><div><div class="brand">HYM // ADMIN PANEL <span class="build">v139</span></div><div class="muted">traffic monitor + public templates · phone / tablet / windows · assets fixed · chat restored · module deploy fixed · client js repaired · mood visible · mood resizable · http redirect</div></div><button id="refresh">Оновити</button></header>
<section class="grid"><article class="card stats"><div class="label">Зараз онлайн</div><div class="n" id="online">—</div><div class="muted">активність за останні 150 секунд</div></article><article class="card stats"><div class="label">Сьогодні на сайті</div><div class="n" id="today">—</div><div class="muted" id="day">Europe/Kyiv</div></article><article class="card stats"><div class="label">Доступні шаблони</div><div class="n" id="count">—</div><div class="muted">серверні HYM presets</div></article>
<article class="card"><h2>Стандартний шаблон телефону</h2><div class="row"><span class="muted">Phone / iOS / Android</span><select id="mobile"></select></div></article><article class="card tablet-template"><h2>Стандартний шаблон планшета <span class="new-badge">TABLET</span></h2><div class="row"><span class="muted">Tablet / Android / iPad</span><select id="tablet"></select></div></article><article class="card"><h2>Стандартний шаблон Windows</h2><div class="row"><span class="muted">Desktop Windows</span><select id="windows"></select></div></article></section><div class="status" id="status"></div></main>
<script>(()=>{const initial=decodeURIComponent(location.pathname.replace(/^\\/hym-admin\\/?/,"").split("/")[0]||"");const key=initial||sessionStorage.getItem("hym_admin_key")||"";if(initial){sessionStorage.setItem("hym_admin_key",initial);history.replaceState({},"","/hym-admin")}const headers={"x-hym-admin-key":key,"content-type":"application/json"};const el=id=>document.getElementById(id);const setStatus=(text,type="")=>{el("status").textContent=text||"";el("status").className="status "+type};function fill(select,presets,active){select.replaceChildren();const none=document.createElement("option");none.value="";none.textContent="— вбудований стандартний шаблон —";select.append(none);presets.forEach(p=>{const option=document.createElement("option");option.value=p.id;option.textContent=(p.name||p.id)+" ["+p.id+"]";option.title=option.textContent;select.append(option)});if(active&&![...select.options].some(o=>o.value===active)){const missing=document.createElement("option");missing.value=active;missing.textContent="⚠ активний asset не знайдено ["+active+"]";select.append(missing)}select.value=active||"";select.title=select.options[select.selectedIndex]?.textContent||""}async function load(){try{setStatus("Оновлення...");const r=await fetch("/api/hym-admin/config",{headers,cache:"no-store"});const d=await r.json();if(!r.ok)throw new Error(d.error||"Помилка доступу");el("online").textContent=d.stats.online;el("today").textContent=d.stats.today;el("day").textContent=d.stats.day+" · Europe/Kyiv";el("count").textContent=d.presets.length;setStatus("Дані оновлено · settings: "+(d.bindings?.settingsStorage||"PRESETS_KV"), "ok");fill(el("mobile"),d.presets,d.active.mobile);fill(el("tablet"),d.presets,d.active.tablet);fill(el("windows"),d.presets,d.active.windows);if(!d.bindings?.adminConfigKv)setStatus("Дані оновлено · ADMIN_CONFIG_KV не підключений, fallback PRESETS_KV", "ok");}catch(e){setStatus(e.message,"err")}}async function save(platform,presetId){try{setStatus("Збереження...");const r=await fetch("/api/hym-admin/active-template",{method:"POST",headers,body:JSON.stringify({platform,presetId})});const d=await r.json();if(!r.ok)throw new Error(d.error||"Не вдалося зберегти");setStatus("Стандартний шаблон для "+platform+" оновлено", "ok")}catch(e){setStatus(e.message,"err");load()}}el("refresh").onclick=load;el("mobile").onchange=e=>{e.target.title=e.target.options[e.target.selectedIndex]?.textContent||"";save("mobile",e.target.value)};el("tablet").onchange=e=>{e.target.title=e.target.options[e.target.selectedIndex]?.textContent||"";save("tablet",e.target.value)};el("windows").onchange=e=>{e.target.title=e.target.options[e.target.selectedIndex]?.textContent||"";save("windows",e.target.value)};load();setInterval(load,30000)})();</script></body></html>`;

function renderAdminPanel(request, url, env) {
  try {
    hymRequireAdmin(request, env, url);
    return new Response(HYM_ADMIN_HTML, { headers: { "content-type": "text/html; charset=UTF-8", "cache-control": "no-store, max-age=0", "x-robots-tag": "noindex, nofollow" } });
  } catch {
    return new Response("Not found", { status: 404, headers: { "content-type": "text/plain; charset=UTF-8", "cache-control": "no-store" } });
  }
}
